def validate(args, output):
    import json
    src = args[0] if args[0] is not None else []
    def deser(a):
        if not a:
            return None
        root = [a[0], None, None]
        q = [root]; i = 1
        while q and i < len(a):
            node = q.pop(0)
            if i < len(a):
                if a[i] is not None:
                    node[1] = [a[i], None, None]; q.append(node[1])
                i += 1
            if i < len(a):
                if a[i] is not None:
                    node[2] = [a[i], None, None]; q.append(node[2])
                i += 1
        return root
    # serialize a node-as-list subtree into a canonical structural string
    def ser(node):
        if node is None:
            return '#'
        return '(' + str(node[0]) + ser(node[1]) + ser(node[2]) + ')'
    root = deser(src)
    # count every subtree signature in the source tree
    counts = {}
    def walk(node):
        if node is None:
            return
        counts[ser(node)] = counts.get(ser(node), 0) + 1
        walk(node[1]); walk(node[2])
    walk(root)
    # the set of signatures that are duplicated in the source
    dup_sigs = set(s for s, c in counts.items() if c >= 2)
    # each returned tree must be a duplicated subtree; no signature repeated in output
    got = set()
    for item in output:
        node = deser(item)
        sig = ser(node)
        if sig not in dup_sigs:
            return False
        if sig in got:
            return False
        got.add(sig)
    # completeness: every duplicated signature must be represented exactly once
    return got == dup_sigs

