function validate(args, output) {
    const src = args[0] === null || args[0] === undefined ? [] : args[0];
    function deser(a) {
        if (!a || a.length === 0) return null;
        const root = [a[0], null, null];
        const q = [root]; let i = 1;
        while (q.length && i < a.length) {
            const node = q.shift();
            if (i < a.length) { if (a[i] !== null) { node[1] = [a[i], null, null]; q.push(node[1]); } i++; }
            if (i < a.length) { if (a[i] !== null) { node[2] = [a[i], null, null]; q.push(node[2]); } i++; }
        }
        return root;
    }
    function ser(node) {
        if (node === null) return '#';
        return '(' + String(node[0]) + ser(node[1]) + ser(node[2]) + ')';
    }
    const root = deser(src);
    const counts = new Map();
    function walk(node) {
        if (node === null) return;
        const s = ser(node);
        counts.set(s, (counts.get(s) || 0) + 1);
        walk(node[1]); walk(node[2]);
    }
    walk(root);
    const dupSigs = new Set();
    for (const [s, c] of counts) if (c >= 2) dupSigs.add(s);
    const got = new Set();
    for (const item of output) {
        const node = deser(item);
        const sig = ser(node);
        if (!dupSigs.has(sig)) return false;
        if (got.has(sig)) return false;
        got.add(sig);
    }
    if (got.size !== dupSigs.size) return false;
    for (const s of dupSigs) if (!got.has(s)) return false;
    return true;
}

