class Solution:
    def findDuplicateSubtrees(self, root):
        from collections import defaultdict
        counts = defaultdict(int)
        first = {}
        def ser(node):
            if node is None:
                return '#'
            sig = '(' + str(node.val) + ser(node.left) + ser(node.right) + ')'
            counts[sig] += 1
            if counts[sig] == 1:
                first[sig] = node
            return sig
        ser(root)
        res = [first[sig] for sig, c in counts.items() if c >= 2]
        # canonical order: sort by signature so all references agree byte-for-byte
        res.sort(key=lambda nd: ser_sig(nd))
        return res


def ser_sig(node):
    if node is None:
        return '#'
    return '(' + str(node.val) + ser_sig(node.left) + ser_sig(node.right) + ')'

