class Solution:
    def findDuplicateSubtrees(self, root):
        from collections import defaultdict
        seen = defaultdict(int)
        rep = {}
        def sig(node):
            if node is None:
                return '#'
            s = str(node.val) + ',' + sig(node.left) + ',' + sig(node.right)
            seen[s] += 1
            if seen[s] == 2:
                rep[s] = node
            return s
        sig(root)
        items = sorted(rep.items(), key=lambda kv: kv[0])
        return [node for _, node in items]

