var findDuplicateSubtrees = function(root) {
    const seen = new Map();
    const rep = new Map();
    const sig = (node) => {
        if (node === null) return '#';
        const s = node.val + ',' + sig(node.left) + ',' + sig(node.right);
        const c = (seen.get(s) || 0) + 1;
        seen.set(s, c);
        if (c === 2) rep.set(s, node);
        return s;
    };
    sig(root);
    const keys = Array.from(rep.keys()).sort();
    return keys.map(k => rep.get(k));
};
